#!/usr/bin/env node
import { mkdir, readFile, writeFile } from 'node:fs/promises';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const scriptDir = path.dirname(fileURLToPath(import.meta.url));
const appRoot = path.resolve(scriptDir, '..');
const templatePath = path.join(appRoot, 'src', 'child-template.js');
const outDir = path.join(appRoot, 'out', 'dev-build');
const childOut = path.join(outDir, 'child.js');
const manifestOut = path.join(outDir, 'manifest.json');
const builtAt = new Date().toISOString();

const childTemplate = await readFile(templatePath, 'utf8');
const generatedChild = [
  `// Generated by apps-core dev:bundle at ${builtAt}.`,
  `globalThis.__POC_DEV_BUNDLE__ = ${JSON.stringify({ builtAt }, null, 2)};`,
  childTemplate
].join('\n');

await mkdir(outDir, { recursive: true });
await writeFile(childOut, generatedChild);
await writeFile(manifestOut, JSON.stringify({ builtAt }, null, 2));

console.log(`[apps-core dev:bundle] wrote ${path.relative(appRoot, childOut)}`);
